/**
 * MedX shell layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * App shell composition of header, sidebar, main.
 */
const SHELL_TOKENS = Object.freeze({
  primary: { value: "layout-shell-primary", scope: "layout" },
  secondary: { value: "layout-shell-secondary", scope: "layout" },
  muted: { value: "layout-shell-muted", scope: "layout" },
  accent: { value: "layout-shell-accent", scope: "layout" },
  surface: { value: "layout-shell-surface", scope: "layout" },
});

const SHELL_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SHELL_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const shellRegistry = new Map();
const SHELL_listeners = new Set();
let SHELL_seq = 0;

function createShellId(prefix = "medx-layout-shell") {
  SHELL_seq += 1;
  return `${prefix}-${SHELL_seq}`;
}

function registerShell(config = {}) {
  const entryId = config.id ?? createShellId();
  const preset = SHELL_PRESETS[config.preset ?? "default"] ?? SHELL_PRESETS.default;
  const token = SHELL_TOKENS[config.token ?? preset.token] ?? SHELL_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SHELL_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  shellRegistry.set(entryId, entry);
  notifyShellListeners("register", entry);
  return entry;
}

function updateShell(id, patch = {}) {
  const entry = shellRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyShellListeners("update", entry);
  return entry;
}

function resolveShell(id) {
  const entry = shellRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listShellEntries(filter = {}) {
  let items = Array.from(shellRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onShellEvent(listener) {
  SHELL_listeners.add(listener);
  return () => SHELL_listeners.delete(listener);
}

function notifyShellListeners(type, entry) {
  for (const listener of SHELL_listeners) {
    try {
      listener({ type, entry, registrySize: shellRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:shell] listener error", err.message);
    }
  }
}

function getShellMetrics() {
  const items = listShellEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SHELL_TOKENS).length,
    presets: Object.keys(SHELL_PRESETS).length,
  };
}

async function runMedxShell() {
  console.log("[medx:ui:layout:shell] runtime initialized");
  console.log(`[medx:ui:layout:shell] tokens=${Object.keys(SHELL_TOKENS).length} presets=${Object.keys(SHELL_PRESETS).length}`);

  const events = [];
  onShellEvent((e) => events.push(e.type));

  const domains = Object.keys(SHELL_SUPPLY_CHAIN);
  const presets = Object.keys(SHELL_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerShell({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/shell" },
    });
  }

  const first = listShellEntries()[0];
  if (first) updateShell(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getShellMetrics();
  const resolved = first ? resolveShell(first.id) : null;

  console.log(`[medx:ui:layout:shell] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:shell] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:shell] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:shell] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:shell] bootstrap complete");
}

module.exports = runMedxShell;
